export type ClaimableLinksInitialMode = "claim" | "create" | "manage";

type DagInfoResponse =
  | {
      network: "mainnet";
      pastMedianTime: string;
      virtualDaaScore: string;
    }
  | {
      error: {
        code: string;
        message: string;
      };
    };

type ClaimableScriptResponse =
  | {
      script: {
        fundingAddress: string;
        linkPublicKey: string;
        network: "mainnet";
        redeemScriptHex: string;
        refundLockTime: string;
        refundPublicKey: string;
        scriptPublicKey: {
          script: string;
          version: number;
        };
        warning: string;
      };
      warning: string;
    }
  | {
      error: {
        code: string;
        message: string;
      };
    };

type FundingStatusResponse =
  | {
      funded: boolean;
      match: null | {
        amountSompi: string;
        blockTime: null | number;
        outputIndex: number;
        transactionId: string;
      };
      outputStatus: "funded_unspent" | "spent" | "unfunded";
      spent: boolean;
      registeredStatus: null | string;
      unmatchedOutputs: UnmatchedFundingOutput[];
      utxoScanAvailable: boolean;
    }
  | {
      error: {
        code: string;
        message: string;
      };
    };

type ClaimableSpend = BrowserClaimableSpend;

type ClaimableBroadcast = {
  submittedTransactionId: string;
  transactionId: string;
};

type ClaimableBroadcastResponse =
  | {
      broadcast: ClaimableBroadcast;
      mismatchRecovery?: boolean;
      warning: string;
    }
  | {
      error: {
        code: string;
        message: string;
      };
    };

type UnmatchedFundingOutput = {
  amountSompi: string;
  outputIndex: number;
  transactionId: string;
};

export type ClaimableLabStatus =
  | "draft"
  | "awaiting_funding"
  | "funded"
  | "shared"
  | "claimed"
  | "refundable"
  | "refunded"
  | "spent_unknown";

