  amountSompi: string;
  claimCode: string;
  claimPublicKey: string;
  createdAt: string;
  createdAtMs: number;
  description: string;
  feeKas: string;
  feeSompi: string;
  fundingMatch: null | {
    amountSompi: string;
    blockTime: null | number;
    outputIndex: number;
    transactionId: string;
  };
  fundingAddress: null | string;
  id: string;
