  async function downloadRecoveryFile() {
    if (!labLink) return;
    setError("");
    const exportedAt = new Date().toISOString();
    try {
      const bundle = createClaimableRecoveryBundle(toClaimableRecoveryRecord(labLink), exportedAt);
      downloadJson(
        `kaspa-links-${safeFilename(labLink.title)}-${safeFilename(labLink.id)}-private-recovery.json`,
        bundle,
      );
      setRecoveryExportedAt(exportedAt);
      try {
        await saveClaimableRecord({
          ...toClaimableStoreRecord(labLink, claimUrl, manageUrl),
          recoveryExportedAt: exportedAt,
        });
        setNotice("Private recovery bundle downloaded. Keep it private and offline.");
      } catch {
        setNotice(
          "Private recovery bundle downloaded. Its saved state could not be recorded in this browser, so keep the file safe.",
        );
      }
    } catch (recoveryError) {
      setError(
        recoveryError instanceof Error
          ? recoveryError.message
          : "Could not create the recovery bundle.",
      );
    }
  }

  async function importRecoveryFile(event: ChangeEvent<HTMLInputElement>) {
    const input = event.currentTarget;
    const file = input.files?.[0];
    if (!file) return;
    setError("");
    setNotice("");

    try {
      if (file.size > 250_000) throw new Error("Recovery file is unexpectedly large.");
      const bundle = parseClaimableRecoveryBundle(await readTextFile(file));
      assertClaimableMatchesRecoveryTarget(bundle.link, recoveryTarget);

      const scriptResponse = await fetch("/api/toccata-lab/claimable-script", {
        body: JSON.stringify({
          linkPublicKey: bundle.link.claimPublicKey,
          refundLockTime: bundle.link.refundLockTime,
          refundPublicKey: bundle.link.refundPublicKey,
        }),
        headers: { "Content-Type": "application/json" },
        method: "POST",
      });
      const scriptBody = (await scriptResponse.json()) as ClaimableScriptResponse;
      if (!scriptResponse.ok || "error" in scriptBody) {
        throw new Error(
          "error" in scriptBody
            ? scriptBody.error.message
            : "Could not verify the recovery contract.",
        );
      }
      if (
        scriptBody.script.fundingAddress !== bundle.link.fundingAddress ||
        scriptBody.script.redeemScriptHex.toLowerCase() !==
          bundle.link.redeemScriptHex.toLowerCase()
      ) {
        throw new Error("Recovery file does not match its claimable contract.");
      }

      const recoveredLink: ClaimableLabLink = {
        ...fromClaimableRecoveryRecord(bundle.link),
        scriptPublicKey: scriptBody.script.scriptPublicKey,
      };
      setLabLink(recoveredLink);
      setAmountKas(recoveredLink.netClaimKas);
      setFeeKas(recoveredLink.feeKas);
      setLinkTitle(recoveredLink.title);
      setLinkDescription(recoveredLink.description);
      setManageOnlyView(true);
      setClaimOnlyView(false);
      setRecoveryExportedAt(bundle.exportedAt);
      setClaimSpend(null);
      setRefundSpend(null);
      setClaimBroadcast(null);
      setRefundBroadcast(null);
      setRefundSendError("");
      setRefundSendNotice("");

      try {
        const existingRecord = (await loadClaimableRecords()).find(
          (record) => record.id === recoveredLink.id,
        );
        const recoveredManageUrl = buildLabManageUrl(recoveredLink);
        await saveClaimableRecord({
          ...toClaimableStoreRecord(
            recoveredLink,
            existingRecord?.claimUrl ?? "",
            recoveredManageUrl || existingRecord?.manageUrl || "",
          ),
          recoveryExportedAt: bundle.exportedAt,
        });
        setNotice(
          `Recovered “${recoveredLink.title}” locally. The refund key was not uploaded. Checking its on-chain status now.`,
        );
      } catch {
        setNotice(
          `Recovered “${recoveredLink.title}” for this tab. The refund key was not uploaded; keep the recovery file safe.`,
        );
      }
    } catch (recoveryError) {
      setError(
        recoveryError instanceof Error
          ? recoveryError.message
          : "Could not import the recovery bundle.",
      );
    } finally {
      input.value = "";
    }
  }

