  async function fundWithKasware() {
    if (!labLink?.fundingAddress) return;
    if (!recoveryExportedAt) {
      setError("Download the private recovery bundle before funding this link.");
      return;
    }

    setError("");
    setNotice("");
    setFundingWithKasware(true);

    try {
      const provider = getKaswareProvider();
      if (!provider) {
        setError("KasWare was not detected. Use the QR code, copy URI, or open this on mobile.");
        return;
      }

      const network = await readKaswareNetwork(provider);
      if (network !== "mainnet") {
        setError(
          network === "unknown"
            ? "Could not verify KasWare network. Switch KasWare to mainnet and retry."
            : `Switch KasWare to mainnet before funding. It is currently on ${network}.`,
        );
        return;
      }

      let confirmedBalanceSompi: bigint | null = null;
      try {
        const balance = await readKaswareBalance(provider);
        confirmedBalanceSompi = balance ? BigInt(balance.confirmed) : null;
      } catch {
        confirmedBalanceSompi = null;
      }
      if (confirmedBalanceSompi !== null) {
        const fundingAmountSompi = BigInt(labLink.amountSompi);
        const spendFeeSompi = BigInt(labLink.feeSompi);
        if (confirmedBalanceSompi < fundingAmountSompi + spendFeeSompi) {
          setError(
            "KasWare's confirmed balance is lower than the funding amount plus fee. Top up the wallet and retry.",
          );
          return;
        }
        if (
          confirmedBalanceSompi - fundingAmountSompi - spendFeeSompi <
          TOCCATA_FUNDING_SAFE_CHANGE_SOMPI
        ) {
          setNotice(
            "Heads up: your KasWare balance leaves only a small change output, which can trip Kaspa's storage-mass limit. If funding is rejected, send from a wallet with a larger, consolidated balance.",
          );
        }
      }

      // KasWare's node WebSocket is sometimes not connected on the very first
      // sendKaspa and works on the next attempt ("WebSocket is not connected").
      // Auto-retry that transient case so the user does not have to reject and
      // try again by hand. Never retry a user rejection or any other error.
      let result: Awaited<ReturnType<typeof sendKaspaPayment>> | null = null;
      for (let attempt = 1; attempt <= 3; attempt += 1) {
        try {
          result = await sendKaspaPayment(provider, {
            amountSompi: BigInt(labLink.amountSompi),
            toAddress: labLink.fundingAddress,
          });
          break;
        } catch (attemptError) {
          const message =
            attemptError instanceof Error ? attemptError.message : String(attemptError);
          const transient = /not connected|websocket|rpc server/i.test(message);
          if (attempt < 3 && transient) {
            setNotice("KasWare is still connecting to the network — retrying…");
            await new Promise((resolve) => window.setTimeout(resolve, 1_200));
            continue;
          }
          throw attemptError;
        }
      }
      if (!result) {
        throw new WalletAdapterError("KasWare did not complete the funding transaction.", {
          code: "funding_failed",
        });
      }

      setNotice(
        result.txId
          ? `Funding transaction sent with KasWare: ${compactHex(result.txId)}. Waiting for the indexer to detect the exact funding output.`
          : "KasWare completed the wallet request without returning a transaction id. Waiting for the indexer to detect the exact funding output.",
      );
      setFundingAutoChecking(true);
      window.setTimeout(() => void checkFundingStatus({ auto: true, quiet: false }), 1_500);
      window.setTimeout(() => void checkFundingStatus({ auto: true, quiet: true }), 5_000);
    } catch (fundingError) {
      setError(
        fundingError instanceof WalletAdapterError
          ? fundingError.message
          : "KasWare did not complete the funding transaction.",
      );
    } finally {
      setFundingWithKasware(false);
    }
  }

  async function checkFundingStatus(options: { auto?: boolean; quiet?: boolean } = {}) {
    if (!labLink) return;

    if (!labLink.fundingAddress) {
      setError("No funding address available yet.");
      return;
    }

    if (!options.quiet) {
      setError("");
      setNotice("");
      setFundingChecking(true);
    }
    if (options.auto) {
      setFundingAutoChecking(true);
    }

    try {
      const response = await fetch("/api/toccata-lab/funding-status", {
        body: JSON.stringify({
          amountSompi: labLink.amountSompi,
          fundingAddress: labLink.fundingAddress,
          fundingOutputIndex: labLink.fundingMatch?.outputIndex,
          fundingTransactionId: labLink.fundingMatch?.transactionId,
          linkKey: labLink.id,
          notBefore: labLink.createdAtMs,
        }),
        headers: { "Content-Type": "application/json" },
        method: "POST",
      });
      const body = (await response.json()) as FundingStatusResponse;
      setFundingLastCheckedAt(Date.now());

      if (!response.ok || "error" in body) {
        if (!options.quiet) {
          setError("error" in body ? body.error.message : "Could not check funding status.");
        }
        return;
      }

      setUnmatchedFundingOutputs(body.unmatchedOutputs);

      if (body.funded && body.match) {
        const registeredTerminalStatus =
          body.registeredStatus === "claimed" ||
          body.registeredStatus === "refunded" ||
          body.registeredStatus === "spent_unknown"
            ? body.registeredStatus
            : null;
        setLabLink((current) => {
          if (!current || current.id !== labLink.id) return current;

          return {
            ...current,
            fundingMatch: body.match,
            status: registeredTerminalStatus
              ? registeredTerminalStatus
              : body.spent
                ? "spent_unknown"
                : current.status === "awaiting_funding"
                  ? "funded"
                  : current.status,
          };
        });

        if (body.spent) {
          if (labLink) {
            void updateClaimableStatus(labLink.id, registeredTerminalStatus ?? "spent_unknown");
          }
          setClaimSpend(null);
          setRefundSpend(null);
          setFundingAutoChecking(false);
          setClaimSendError("");
          setClaimSendNotice(
            "This claim link has already been claimed or spent on-chain. It cannot be claimed again.",
          );
          if (!options.quiet) {
            setNotice("This funding output has already been spent. The claim link is closed.");
          }
          return;
        }

        setFundingAutoChecking(false);
        if (!options.quiet) {
          setNotice("Funding detected. The claim link can now be shared.");
        }
      } else if (!options.quiet) {
        setNotice(
          body.unmatchedOutputs.length > 0
            ? "A payment reached this address, but it does not match the required funding output. Review it below."
            : "No exact funding transaction detected yet.",
        );
      }
    } catch {
      if (!options.quiet) {
        setError("Could not reach the funding status endpoint.");
      }
    } finally {
      if (!options.quiet) {
        setFundingChecking(false);
      }
    }
  }

